import { verify } from 'vex-sdk';

import { agent } from './langchain-agent';

const safeAgentCall = async (input: string) => {
  const result = await verify({
    fn: async () => {
      return await agent.call({ input });
    },
    guards: [
      'code_safety',
      'syntax_validity',
      'no_credential_leakage',
      'execution_sandboxing'
    ],
    riskProfile: 'high',
    maxIterations: 5
  });

  return result;
};

